def student_name():
    name = 'Студент'
    return name

def student_age():
    age = 18
    return age

def increment(value):
    value = value + 1
    return value

def decrement(value):
    value = value - 1
    return value

def is_even(n):
    if n % 2 == 0:
        return True
    return False

def sign(n):
    if n >= 0:
        return 'positive'
    return 'negative'

def exam_result(score):
    if score >= 60:
        return 'pass'
    return 'fail'

def age_group(age):
    if age < 18:
        return 'child'
    return 'adult'

def sum_to_n(n):
    total = 0
    for number in range(1, n + 1):
        total += number
    return total

def factorial_four():
    result = 1
    for number in range(1, 5):
        result *= number
    return result

def count_letters(text):
    total = 0
    for _ in text:
        total += 1
    return total

def join_with_dash(chars):
    result = ''
    for index, char in enumerate(chars):
        if index > 0:
            result += '-'
        result += char
    return result

def first_even(numbers):
    for number in numbers:
        if number % 2 == 0:
            return number
    return None

def count_until_stop(words):
    total = 0
    for word in words:
        if word == 'stop':
            break
        total += 1
    return total

def add_item(items, value):
    items.append(value)
    return items

def sum_list(numbers):
    total = 0
    for number in numbers:
        total += number
    return total

def max_item(numbers):
    current = numbers[0]
    for number in numbers:
        if number > current:
            current = number
    return current

def even_numbers(numbers):
    result = []
    for number in numbers:
        if number % 2 == 0:
            result.append(number)
    return result

def long_words(words):
    result = []
    for word in words:
        if len(word) >= 5:
            result.append(word)
    return result

def add_grade(profile, grade):
    profile['grade'] = grade
    return profile

def sum_scores(scores):
    total = 0
    for value in scores.values():
        total += value
    return total

def positive_entries(data):
    result = {}
    for key, value in data.items():
        if value > 0:
            result[key] = value
    return result

def short_keys(data):
    result = {}
    for key, value in data.items():
        if len(key) == 1:
            result[key] = value
    return result

def minimum(a, b):
    if a < b:
        return a
    return b

def max_of_three(a, b, c):
    result = a
    if b > result:
        result = b
    if c > result:
        result = c
    return result

def average(numbers):
    total = 0
    for number in numbers:
        total += number
    return total / len(numbers)

def vowel_count(text):
    vowels = 'аеёиоуыэюяAEIOUYaeiouy'
    total = 0
    for char in text.lower():
        if char in 'аеёиоуыэюя':
            total += 1
    return total

def first_line(lines):
    if not lines:
        return ''
    return lines[0]

def word_count(text):
    if text == '':
        return 0
    return len(text.split())

def clean_lines(lines):
    result = []
    for line in lines:
        result.append(line.strip())
    return result

def non_empty(lines):
    result = []
    for line in lines:
        if line != '':
            result.append(line)
    return result

def any_line_contains(lines, part):
    for line in lines:
        if part in line:
            return True
    return False

def safe_divide(a, b):
    try:
        return a / b
    except ZeroDivisionError:
        return 0

def safe_int(value):
    try:
        return int(value)
    except ValueError:
        return 0

def safe_get(items, index):
    try:
        return items[index]
    except IndexError:
        return 'error'

def safe_key(data, key):
    try:
        return data[key]
    except KeyError:
        return None

def positive_number(value):
    if value > 0:
        return value
    return 0

def parse_float(text):
    try:
        return float(text)
    except ValueError:
        return 0.0

def age_status(age):
    if age >= 18:
        return 'adult'
    return 'minor'

